return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var rows = 4;
    var cols = 5;
    var cellWidth = 50;
    var cellHeight = 40;

    var startX = (W - cols * cellWidth) / 2;
    var startY = (H - rows * cellHeight) / 2 + 10;

    // Animation phases (10s cycle)
    var duration = 10000;
    var progress = (t % duration) / duration;

    var p1 = 0.20; // 0 to 2s: Initial state
    var p2 = 0.50; // 2s to 5s: Sieve multiples of 2
    var p3 = 0.80; // 5s to 8s: Sieve multiples of 3
    var p4 = 0.95; // 8s to 9.5s: Reveal primes

    // Numbers 2 to 21
    var numbers = [];
    for (var i = 2; i <= 21; i++) {
      numbers.push(i);
    }

    // Helper to get number status
    function getStatus(num) {
      if (progress < p1) {
        return 'neutral';
      }
      if (progress >= p1 && progress < p2) {
        if (num === 2) return 'prime-prime';
        if (num % 2 === 0) return 'crossed-2';
        return 'neutral';
      }
      if (progress >= p2 && progress < p3) {
        if (num === 2 || num === 3) return 'prime-prime';
        if (num % 2 === 0) return 'crossed-2';
        if (num % 3 === 0) return 'crossed-3';
        return 'neutral';
      }
      // Reveal all remaining primes
      var isPrime = [2, 3, 5, 7, 11, 13, 17, 19].indexOf(num) !== -1;
      if (isPrime) return 'prime-final';
      if (num % 2 === 0) return 'crossed-2';
      if (num % 3 === 0) return 'crossed-3';
      return 'crossed-other';
    }

    // Draw grid
    for (var r = 0; r < rows; r++) {
      for (var c = 0; c < cols; c++) {
        var idx = r * cols + c;
        var num = numbers[idx];

        var cx = startX + c * cellWidth + cellWidth / 2;
        var cy = startY + r * cellHeight + cellHeight / 2;

        var status = getStatus(num);

        // Circle background based on status
        ctx.beginPath();
        ctx.arc(cx, cy, 15, 0, Math.PI * 2);

        if (status === 'neutral') {
          ctx.fillStyle = '#374151';
          ctx.fill();
          ctx.fillStyle = '#FFFFFF';
        } else if (status === 'prime-prime') {
          ctx.fillStyle = '#3B82F6'; // Blue for active prime filter
          ctx.fill();
          ctx.fillStyle = '#FFFFFF';
        } else if (status === 'prime-final') {
          var pulse = Math.sin(t * 0.01) * 2;
          ctx.fillStyle = '#10B981'; // Green for final primes
          ctx.beginPath();
          ctx.arc(cx, cy, 15 + pulse, 0, Math.PI * 2);
          ctx.fill();
          ctx.fillStyle = '#FFFFFF';
        } else if (status === 'crossed-2') {
          ctx.strokeStyle = '#EF4444';
          ctx.lineWidth = 1.5;
          ctx.stroke();
          ctx.fillStyle = '#6B7280';
        } else if (status === 'crossed-3') {
          ctx.strokeStyle = '#F59E0B';
          ctx.lineWidth = 1.5;
          ctx.stroke();
          ctx.fillStyle = '#6B7280';
        } else {
          ctx.strokeStyle = '#4B5563';
          ctx.lineWidth = 1.5;
          ctx.stroke();
          ctx.fillStyle = '#6B7280';
        }

        // Number text
        ctx.font = 'bold 13px -apple-system, sans-serif';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(num.toString(), cx, cy);

        // Draw diagonal cross-out line if crossed
        if (status.indexOf('crossed') !== -1) {
          ctx.strokeStyle = '#EF4444';
          ctx.lineWidth = 2;
          ctx.beginPath();
          ctx.moveTo(cx - 10, cy - 10);
          ctx.lineTo(cx + 10, cy + 10);
          ctx.stroke();
        }
      }
    }

    // Top Label
    ctx.fillStyle = '#F3F4F6';
    ctx.font = 'bold 16px -apple-system, sans-serif';
    ctx.textAlign = 'center';

    if (progress < p1) {
      ctx.fillText('List numbers starting from 2...', W / 2, startY - 25);
    } else if (progress < p2) {
      ctx.fillText('Filter multiples of 2 (in red)', W / 2, startY - 25);
    } else if (progress < p3) {
      ctx.fillText('Filter multiples of 3 (in orange)', W / 2, startY - 25);
    } else {
      ctx.fillText('Remaining numbers are Primes!', W / 2, startY - 25);
    }
  }
};
